INSERT INTO articles (id, title, slug, lead, content, category_id, status, published_at, views) VALUES
(
  'd1000000-0000-4000-a000-000000000001',
  'Антитеррористическая безопасность — приоритет в работе Минтруда Ингушетии',
  'antiterroristicheskaya-bezopasnost-prioritet-mintruda',
  'В системе Министерства труда Ингушетии на постоянной основе ведётся работа по обеспечению антитеррористической защищённости подведомственных учреждений.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"В системе Министерства труда, занятости и социального развития Республики Ингушетия на постоянной основе ведётся работа по обеспечению антитеррористической защищённости подведомственных учреждений."}]},{"type":"paragraph","content":[{"type":"text","text":"По поручению заместителя Председателя Правительства — министра труда Ингушетии Хаджибекира Муталиева данному направлению уделяется повышенное внимание. Регулярно проводятся проверки объектов, заседания профильных комиссий, инструктажи и тренировки для сотрудников по действиям в случае возникновения угроз."}]},{"type":"paragraph","content":[{"type":"text","text":"Отдельное внимание уделяется летнему периоду, когда в детском оздоровительном лагере «Аьрзи» проходит отдых детей. На месте организуются профилактические мероприятия по вопросам безопасности. К работе привлекаются представители правоохранительных органов, которые проводят встречи с детьми и разъясняют основные правила поведения в чрезвычайных ситуациях."}]},{"type":"paragraph","content":[{"type":"text","text":"Благодаря системной и последовательной работе за всё время функционирования учреждений, находящихся в ведении министерства, не было зафиксировано ни одного происшествия террористического характера. Работа в этом направлении продолжается на постоянной основе, а обеспечение безопасности получателей социальных услуг и сотрудников остаётся одной из ключевых задач ведомства."}]}]}',
  'c1000000-0000-4000-a000-000000000003',
  'published',
  '2026-03-05T09:55:00Z',
  134
),
(
  'd1000000-0000-4000-a000-000000000002',
  'Стартовала заявочная кампания на квоту целевого обучения на 2027-2028 год',
  'startovala-zayavochnaya-kampaniya-tselevoe-obuchenie-2027',
  'С 1 марта 2026 года на платформе «Работа в России» начался приём заявок на получение квоты для целевого обучения на 2027-2028 учебные года.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"С 1 марта 2026 года на Единой цифровой платформе в сфере занятости и трудовых отношений «Работа в России» начался приём заявок на получение квоты для целевого обучения на 2027-2028 учебные года. Кампания продлится до 31 марта 2026 года включительно."}]},{"type":"paragraph","content":[{"type":"text","text":"Подача заявки через платформу является обязательным условием для получения квоты. Начиная с 2026 года, квота приёма на целевое обучение по программам высшего образования за счёт средств федерального бюджета закрепляется за конкретным работодателем или заказчиком, заявившим о потребности в установленный период."}]},{"type":"paragraph","content":[{"type":"text","text":"Обязательным требованием для участия в кампании является регистрация организации на платформе «Работа в России» через Единую систему идентификации и аутентификации (ЕСИА). При отсутствии регистрации подать заявку на получение квоты будет невозможно."}]},{"type":"paragraph","content":[{"type":"text","text":"Если организация не направит заявку в установленный срок, квота за ней закреплена не будет. Соответственно, она не сможет заключить договор о целевом обучении в пределах бюджетной квоты по программам высшего образования."}]},{"type":"paragraph","content":[{"type":"text","text":"Особенностью кампании 2026 года является расширение круга участников. Получить квоту смогут не только заказчики, указанные в статье 71.1 Федерального закона «Об образовании в Российской Федерации», но и работодатели, не относящиеся к данной категории."}]}]}',
  'c1000000-0000-4000-a000-000000000009',
  'published',
  '2026-03-04T11:42:00Z',
  98
),
(
  'd1000000-0000-4000-a000-000000000003',
  'В Ингушетии стало доступно цифровое удостоверение льготника в мессенджере MAX',
  'v-ingushetii-tsifrovoe-udostoverenie-lgotnika-max',
  'Жители Ингушетии, относящиеся к льготным категориям граждан, теперь могут подтверждать свой статус с помощью QR-кода в мессенджере MAX.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Жители Ингушетии, относящиеся к льготным категориям граждан, теперь могут подтверждать свой статус с помощью QR-кода в мессенджере MAX."}]},{"type":"paragraph","content":[{"type":"text","text":"Цифровое удостоверение представляет собой электронный идентификатор, который позволяет подтвердить право на льготы без необходимости предъявлять бумажные документы. С его помощью можно получать скидки в торговых точках и аптеках, посещать музеи, выставки и театры, а также подтверждать право на льготный проезд в общественном транспорте."}]},{"type":"paragraph","content":[{"type":"text","text":"Новый формат доступен многодетным семьям, пенсионерам и гражданам с инвалидностью. Отдельное заявление для оформления QR-кода подавать не требуется — у пенсионеров код автоматически формируется в личном кабинете на портале «Госуслуги» и доступен с мобильного устройства."}]},{"type":"paragraph","content":[{"type":"text","text":"При сканировании QR-кода подтверждается исключительно льготный статус гражданина. Персональные данные — включая размер пенсии, группу инвалидности и другие сведения — не отображаются. Один и тот же код действует на всей территории Российской Федерации."}]},{"type":"paragraph","content":[{"type":"text","text":"Создание цифрового ID носит добровольный характер. Граждане вправе самостоятельно выбирать удобный способ подтверждения льгот — в цифровом формате или с использованием традиционных документов."}]}]}',
  'c1000000-0000-4000-a000-000000000003',
  'published',
  '2026-03-03T16:53:00Z',
  156
),
(
  'd1000000-0000-4000-a000-000000000004',
  'От кризиса к рекордам: 7 лет преображения социальной сферы Ингушетии',
  'ot-krizisa-k-rekordam-7-let-preobrazheniya-sotsialnoj-sfery',
  'Семилетний этап развития Минтруда Ингушетии стал периодом системных преобразований, масштабного строительства и устойчивого снижения безработицы.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Семилетний этап развития Министерства труда, занятости и социального развития Республики Ингушетия стал периодом системных преобразований, масштабного инфраструктурного строительства и устойчивого снижения безработицы."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Рекордное снижение безработицы"}]},{"type":"paragraph","content":[{"type":"text","text":"В 2019 году уровень регистрируемой безработицы составлял 9,7%. По итогам 2026 года показатель снизился до 5,6%. Снижение составило 4,1 процентных пункта — это исторический минимум регистрируемой безработицы за последние годы."}]},{"type":"paragraph","content":[{"type":"text","text":"Особо сложным стал 2020 год: в период пандемии COVID-19 общий уровень безработицы в Ингушетии вырос до 30,2%. Перед руководством региона стояла задача не только стабилизировать ситуацию, но и заложить фундамент для долгосрочного развития."}]},{"type":"paragraph","content":[{"type":"text","text":"Ключевыми инструментами стали создание промышленного парка, легализация сотен теневых предприятий и активная реализация программы государственного социального контракта. Благодаря этой мере малоимущие граждане получили возможность открыть собственное дело и выйти на стабильный доход."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Новая социальная инфраструктура"}]},{"type":"paragraph","content":[{"type":"text","text":"В рамках регионального проекта «Старшее поколение» в республике создана полноценная система долговременного ухода за пожилыми гражданами и инвалидами. Построен новый корпус стационарного обслуживания в Малгобеке, введён в эксплуатацию «Дом ветеранов» в с.п. Сурхахи на 50 мест."}]},{"type":"paragraph","content":[{"type":"text","text":"После масштабной реконструкции оздоровительный лагерь «Эрзи» способен принимать до 430 детей в смену вместо прежних 300. Модернизирована инфраструктура, повышены стандарты безопасности, обновлено оборудование."}]},{"type":"paragraph","content":[{"type":"text","text":"За семь лет Минтруда Ингушетии продемонстрировало системную модель управления: от преодоления кризисного периода пандемии до выхода на исторический минимум по безработице и формирования современной социальной инфраструктуры."}]}]}',
  'c1000000-0000-4000-a000-000000000003',
  'published',
  '2026-02-18T10:51:00Z',
  287
),
(
  'd1000000-0000-4000-a000-000000000005',
  'В Ингушетии стартует Всероссийский опрос работодателей',
  'v-ingushetii-startuet-vserossijskij-opros-rabotodatelej',
  'Всероссийский опрос определит кадровые потребности региона на ближайшие семь лет — с 2027 по 2033 годы.',
  '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"В Республике Ингушетия стартует Всероссийский опрос работодателей, который определит кадровые потребности региона на ближайшие семь лет — с 2027 по 2033 годы. От того, насколько активно предприятия примут участие в анкетировании, зависит формирование будущей кадровой политики и подготовка востребованных специалистов."}]},{"type":"paragraph","content":[{"type":"text","text":"Опрос проводится на цифровой платформе «Работа в России» по инициативе Министерства труда и социальной защиты Российской Федерации. В Ингушетии координацию работы осуществляет Министерство труда, занятости и социального развития республики."}]},{"type":"paragraph","content":[{"type":"text","text":"Главная задача — получить точные данные о том, какие специалисты, в каких отраслях и в каком количестве будут нужны экономике региона в перспективе семи лет. Эти сведения станут основой для корректировки контрольных цифр приёма в колледжи и вузы."}]},{"type":"paragraph","content":[{"type":"text","text":"Для участия работодателям необходимо зарегистрировать организацию на платформе «Работа в России». Личный кабинет создаётся руководителем организации через портал Госуслуг при наличии подтверждённой учётной записи и усиленной квалифицированной электронной подписи."}]},{"type":"paragraph","content":[{"type":"text","text":"Участие в опросе — это возможность для бизнеса напрямую повлиять на формирование кадрового резерва республики. Чем точнее будут предоставленные данные сегодня, тем эффективнее будет выстроена система подготовки специалистов и тем устойчивее станет рынок труда Ингушетии."}]}]}',
  'c1000000-0000-4000-a000-000000000002',
  'published',
  '2026-02-18T10:47:00Z',
  173
);

